"""End-to-end integration tests and regression tests for fused matmul pipeline."""

import pytest
import json
import sys
import os

sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..', '..', 'script'))

from dataset_generator.mlir_analyzer import HighLevelMLIRAnalyzer
from dataset_generator.compiler import generate_all_mlir_files, generate_pattern_compile_report
from dataset_generator.shape_source import build_stats_from_shape_source
from .fused_fixtures import DISPATCH_F32_BIAS_ADD, DISPATCH_I8_REQUANT


class TestFusedPipelineEndToEnd:

    def test_f32_bias_add_end_to_end(self, tmp_path):
        """Full pipeline: dispatch MLIR -> extract template -> build stats -> generate MLIR files."""
        analyzer = HighLevelMLIRAnalyzer(metadata_path="/nonexistent")
        template, extra_inputs_spec = analyzer.extract_fused_template(DISPATCH_F32_BIAS_ADD)

        stats = {
            'named_ops': {
                'linalg.matmul': {
                    'iterator_types': ['parallel', 'parallel', 'reduction'],
                    'template': 'linalg.matmul ins(%0, %1 : tensor<{M}x{K}x{dtype}>, tensor<{K}x{N}x{dtype}>) outs(%2 : tensor<{M}x{N}x{dtype}>)',
                    'total_count': 1,
                    'shape_patterns': [
                        {
                            'inputs': [{'shape': [64, 32], 'dtype': 'f32'}, {'shape': [32, 128], 'dtype': 'f32'}],
                            'outputs': [{'shape': [64, 128], 'dtype': 'f32'}],
                            'default_tile_config': {'tile_sizes': [[32, 64, 0], [32, 64, 0], [0, 0, 0], [4, 64, 0], [0, 0, 1], [0, 0, 0]]},
                            'op_pattern_id': '0',
                            'source_file': 'test.mlir',
                        },
                    ],
                },
            },
            'generic_ops': {},
            'fused_ops': {
                'abc123': {
                    'fingerprint': 'LINALG.FILL -> LINALG.MATMUL -> GENERIC_P_01_01_addf',
                    'primary_op': 'linalg.matmul',
                    'template': template,
                    'extra_inputs_spec': extra_inputs_spec,
                    'iterator_types': ['parallel', 'parallel', 'reduction'],
                    'total_count': 1,
                    'shape_patterns': [
                        {
                            'inputs': [{'shape': [64, 32], 'dtype': 'f32'}, {'shape': [32, 128], 'dtype': 'f32'}],
                            'outputs': [{'shape': [64, 128], 'dtype': 'f32'}],
                            'default_tile_config': {'tile_sizes': [[32, 64, 0], [32, 64, 0], [0, 0, 0], [4, 64, 0], [0, 0, 1], [0, 0, 0]]},
                            'op_pattern_id': '0',
                            'source_file': 'test.mlir',
                        },
                    ],
                },
            },
        }

        output_dir = tmp_path / "MLIR-files"
        generated = generate_all_mlir_files(stats, output_dir, op_filter='matmul')

        standalone_files = [g for g in generated if 'matmul_fused' not in str(g[0])]
        fused_files = [g for g in generated if 'matmul_fused' in str(g[0])]
        assert len(standalone_files) >= 1, "Should generate standalone matmul files"
        assert len(fused_files) >= 1, "Should generate fused matmul files"

        fused_path = fused_files[0][0]
        content = fused_path.read_text()

        assert 'tensor<64x32xf32>' in content
        assert 'tensor<32x128xf32>' in content
        assert 'tensor<64x128xf32>' in content
        assert 'tensor<784x' not in content
        assert 'tensor<512x' not in content
        assert 'linalg.fill' in content
        assert 'linalg.matmul' in content
        assert 'linalg.generic' in content
        assert 'module {' in content
        assert 'func.func @main(' in content
        assert '--input=' in content

    def test_i8_requant_end_to_end(self, tmp_path):
        """Full pipeline for i8 requant: dispatch -> template -> shape source -> generate."""
        analyzer = HighLevelMLIRAnalyzer(metadata_path="/nonexistent")
        template, extra_inputs_spec = analyzer.extract_fused_template(DISPATCH_I8_REQUANT)

        assert len(extra_inputs_spec) == 3

        patterns_data = {
            'named_ops': {
                'linalg.matmul': {
                    'iterator_types': ['parallel', 'parallel', 'reduction'],
                    'template': 'linalg.matmul ...',
                    'shape_patterns': [
                        {
                            'inputs': [{'shape': [1024, 192], 'dtype': 'i8'}, {'shape': [192, 768], 'dtype': 'i8'}],
                            'outputs': [{'shape': [1024, 768], 'dtype': 'i32'}],
                            'default_tile_config': {'tile_sizes': [[64, 64, 0], [64, 64, 0], [0, 0, 0], [8, 32, 0], [0, 0, 1], [0, 0, 0]]},
                        },
                    ],
                },
            },
            'generic_ops': {},
            'fused_ops': {
                'def456': {
                    'fingerprint': 'LINALG.FILL -> LINALG.MATMUL -> GENERIC_P_01_1_1_1_01_requant',
                    'primary_op': 'linalg.matmul',
                    'template': template,
                    'extra_inputs_spec': extra_inputs_spec,
                    'iterator_types': ['parallel', 'parallel', 'reduction'],
                    'total_count': 1,
                    'shape_patterns': [],
                },
            },
        }

        shape_file = tmp_path / "matmul_shapes.txt"
        shape_file.write_text("256x128x64xi8\n")

        stats = build_stats_from_shape_source(str(shape_file), patterns_data, 'matmul')

        assert 'fused_ops' in stats
        assert 'def456' in stats['fused_ops']
        fused_entry = stats['fused_ops']['def456']
        assert len(fused_entry['shape_patterns']) == 1
        assert fused_entry['shape_patterns'][0]['inputs'][0]['dtype'] == 'i8'

        output_dir = tmp_path / "MLIR-files"
        generated = generate_all_mlir_files(stats, output_dir, op_filter='matmul')

        fused_files = [g for g in generated if 'matmul_fused' in str(g[0])]
        assert len(fused_files) >= 1

        content = fused_files[0][0].read_text()

        assert 'tensor<256x64xi8>' in content
        assert 'tensor<64x128xi8>' in content
        assert 'tensor<128xi32>' in content
        assert 'tensor<128xi8>' in content
        assert 'arith.addi' in content
        assert 'tosa.apply_scale' in content
        assert 'arith.trunci' in content


