class TestBuildMatmulShapePattern:

    def test_build_matmul_shape_pattern_i8(self):
        # dims = [M, N, K], dtype = 'i8'
        # A[M,K] x B[K,N] -> C[M,N]
        pattern = build_matmul_shape_pattern([4, 480, 128], 'i8')
        assert pattern['inputs'][0]['shape'] == [4, 128]
        assert pattern['inputs'][0]['dtype'] == 'i8'
        assert pattern['inputs'][1]['shape'] == [128, 480]
        assert pattern['inputs'][1]['dtype'] == 'i8'
        assert pattern['outputs'][0]['shape'] == [4, 480]
        assert pattern['outputs'][0]['dtype'] == 'i32'
        assert pattern['all_dims'] == [4, 480, 128]

    def test_build_matmul_shape_pattern_f32(self):
        pattern = build_matmul_shape_pattern([256, 1024, 512], 'f32')
        assert pattern['inputs'][0]['shape'] == [256, 512]
        assert pattern['inputs'][0]['dtype'] == 'f32'
        assert pattern['inputs'][1]['shape'] == [512, 1024]
        assert pattern['inputs'][1]['dtype'] == 'f32'
        assert pattern['outputs'][0]['shape'] == [256, 1024]
        assert pattern['outputs'][0]['dtype'] == 'f32'
        assert pattern['all_dims'] == [256, 1024, 512]

    def test_build_matmul_roundtrip_get_dim_sizes(self):
        """Test #12: feed matmul pattern into get_dim_sizes_from_shape_pattern."""
        pattern = build_matmul_shape_pattern([256, 1024, 512], 'f32')
        iterator_types = ['parallel', 'parallel', 'reduction']
        dim_sizes = get_dim_sizes_from_shape_pattern(
            'linalg.matmul', iterator_types, pattern
        )
        # get_dim_sizes_from_shape_pattern returns [M, N, K]
        assert dim_sizes == [256, 1024, 512]


