class TestBuildStatsFromShapeSource:

    def _setup_files(self, tmp_path, shapes_text=None, patterns_data=None):
        """Helper to create shape file and pattern source."""
        shape_file = tmp_path / "shapes.txt"
        if shapes_text is None:
            shapes_text = "4x480x128xi8\n256x1024x512xf32\n"
        shape_file.write_text(shapes_text)

        pattern_file = tmp_path / "patterns.json"
        if patterns_data is None:
            patterns_data = {
                "named_ops": {
                    "linalg.matmul": {
                        "iterator_types": ["parallel", "parallel", "reduction"],
                        "total_count": 0,
                        "shape_patterns": []
                    }
                },
                "generic_ops": {}
            }
        pattern_file.write_text(json.dumps(patterns_data))
        return str(shape_file), str(pattern_file)

    def test_build_stats_from_shape_source_matmul(self, tmp_path):
        shape_file, pattern_file = self._setup_files(tmp_path)
        stats = build_stats_from_shape_source(shape_file, pattern_file, 'matmul')

        assert "named_ops" in stats
        assert "linalg.matmul" in stats["named_ops"]
        op_data = stats["named_ops"]["linalg.matmul"]
        assert op_data["iterator_types"] == ["parallel", "parallel", "reduction"]
        assert len(op_data["shape_patterns"]) == 2
        # First shape: 4x480x128xi8 -> M=4, N=480, K=128
        p0 = op_data["shape_patterns"][0]
        assert p0["inputs"][0]["shape"] == [4, 128]
        assert p0["inputs"][1]["shape"] == [128, 480]
        assert p0["outputs"][0]["shape"] == [4, 480]

    def test_build_stats_shape_patterns_structure(self, tmp_path):
        shape_file, pattern_file = self._setup_files(
            tmp_path, shapes_text="64x256x128xf32\n"
        )
        stats = build_stats_from_shape_source(shape_file, pattern_file, 'matmul')
        op_data = stats["named_ops"]["linalg.matmul"]
        pattern = op_data["shape_patterns"][0]
        assert "inputs" in pattern
        assert "outputs" in pattern
        assert "all_dims" in pattern
        assert "count" in pattern
        assert op_data["total_count"] == 1

    def test_build_stats_missing_op_raises(self, tmp_path):
        shape_file, pattern_file = self._setup_files(tmp_path)
        with pytest.raises(ValueError, match="not found in pattern source"):
            build_stats_from_shape_source(shape_file, pattern_file, 'batch_matmul')

    def test_build_stats_copies_template(self, tmp_path):
        """template from pattern source should be propagated to stats."""
        patterns_data = {
            "named_ops": {
                "linalg.matmul": {
                    "iterator_types": ["parallel", "parallel", "reduction"],
                    "template": "linalg.matmul ins(%0, %1 : tensor<{M}x{K}x{dtype}>)",
                    "total_count": 0,
                    "shape_patterns": []
                }
            },
            "generic_ops": {}
        }
        shape_file, pattern_file = self._setup_files(
            tmp_path, shapes_text="64x256x128xf32\n", patterns_data=patterns_data
        )
        stats = build_stats_from_shape_source(shape_file, pattern_file, 'matmul')
        assert "template" in stats["named_ops"]["linalg.matmul"]
        assert "{M}" in stats["named_ops"]["linalg.matmul"]["template"]


